// Примечание: требует C++26 std::execution (P2300).
// Показан как спецификационный пример — без компиляции.
#include <execution>
#include <print>

int main() {
    // just(42) — sender, который немедленно завершается со значением 42.
    // sync_wait блокирует текущий поток до завершения sender-а,
    // возвращает optional<tuple<int>>.
    auto result = std::execution::sync_wait(
        std::execution::just(42)
    );

    // *result — это tuple<int>{42}
    std::println("{}", std::get<0>(*result)); // выведет: 42
}

// Три типа sender-ов — три канала завершения.
// Показан как спецификационный пример.
#include <execution>
#include <print>

int main() {
    // Канал 1: set_value(42)
    auto val_sender = std::execution::just(42);
    auto r1 = std::execution::sync_wait(val_sender);
    // r1 == optional<tuple<int>>{42}

    // Канал 2: set_error(exception_ptr)
    auto err_sender = std::execution::just_error(
        std::make_exception_ptr(std::runtime_error{"fail"}));
    // sync_wait пробросит исключение из exception_ptr

    // Канал 3: set_stopped()
    auto stop_sender = std::execution::just_stopped();
    auto r3 = std::execution::sync_wait(stop_sender);
    // r3 == std::nullopt  (отмена — не ошибка, просто нет результата)

    std::println("value: {}",  std::get<0>(*r1)); // 42
    std::println("stopped: {}", !r3.has_value());  // true
}

// then() принимает sender и функцию, возвращает новый sender.
// Цепочка строится лениво — пока не вызван sync_wait.
#include <execution>
#include <print>

int main() {
    // Каждый | строит новый sender, ничего не запуская.
    auto pipeline =
        std::execution::just(10)
        | std::execution::then([](int x) { return x * 3; })
        | std::execution::then([](int x) { return x + 2; });

    // sync_wait запускает весь граф за один раз.
    auto result = std::execution::sync_wait(std::move(pipeline));
    std::println("{}", std::get<0>(*result)); // (10 * 3) + 2 == 32
}

