#include <print>
#include <stdexcept>

int main() {
    namespace ex = std::execution;

    // Отмена: sync_wait возвращает nullopt
    auto r1 = ex::sync_wait(ex::just_stopped());
    if (!r1) {
        std::println("cancelled");  // выводится
    }

    // Ошибка: sync_wait пробрасывает исключение
    try {
        ex::sync_wait(
            ex::just_error(
                std::make_exception_ptr(std::runtime_error{"oops"})
            )
        );
    } catch (const std::runtime_error& e) {
        std::println("error: {}", e.what());  // error: oops
    }
}

