#include <execution>
#include <stdexcept>
#include <iostream>

int main() {
    namespace ex = std::execution;

    auto result = ex::sync_wait(
        ex::just_error(
            std::make_exception_ptr(std::runtime_error{"oops"})
        )
        | ex::upon_error([](std::exception_ptr) {
            return -1;  // ошибка → резервное значение
        })
        | ex::then([](int v) { return v * 2; })
    );

    // upon_error перехватил set_error и вернул -1
    // then(-1 * 2) = -2
    // *result == tuple{-2}
    auto [v] = *result;
    std::cout << v << '\n';  // -2
}

#include <execution>
#include <iostream>
#include <thread>

int main() {
    namespace ex = std::execution;

    ex::run_loop loop;
    auto sch = loop.get_scheduler();

    // Запускаем цепочку асинхронно
    // (в реальном коде loop.run() вызывается в отдельном потоке)
    std::jthread worker([&loop]{ loop.run(); });

    auto result = ex::sync_wait(
        ex::schedule(sch)          // переходим в контекст loop
        | ex::then([](){ return 42; })   // выполняется на loop
        | ex::then([](int x){ return x * 2; }) // тоже на loop
    );

    loop.finish();

    // *result == tuple{84}
    auto [v] = *result;
    std::cout << v << '\n';  // 84
}

