#include <execution>
#include <iostream>
#include <chrono>
#include <thread>

int compute_a() {
    // симулируем работу
    std::this_thread::sleep_for(std::chrono::milliseconds{100});
    return 6;
}

int compute_b() {
    std::this_thread::sleep_for(std::chrono::milliseconds{80});
    return 7;
}

int main() {
    namespace ex = std::execution;

    std::execution::thread_pool pool{2};  // два рабочих потока
    auto sch = pool.get_scheduler();

    // Оба вычисления запускаются одновременно:
    // compute_a() и compute_b() работают параллельно.
    auto result = ex::sync_wait(
        ex::when_all(
            ex::schedule(sch) | ex::then([]{ return compute_a(); }),
            ex::schedule(sch) | ex::then([]{ return compute_b(); })
        )
    );

    // result = std::optional<std::tuple<int, int>>
    // Порядок совпадает с порядком аргументов when_all,
    // а не с порядком завершения.
    auto [r1, r2] = *result;
    std::cout << r1 << " * " << r2 << " = " << r1 * r2 << '\n';
    // Ожидаемый вывод: 6 * 7 = 42
}

#include <execution>
#include <iostream>
#include <stdexcept>

int main() {
    namespace ex = std::execution;

    std::execution::thread_pool pool{2};
    auto sch = pool.get_scheduler();

    // Первый сендер всегда падает с ошибкой.
    // Второй — «долгое» вычисление, которое должно получить
    // stop_requested и завершиться через set_stopped.
    auto result = ex::sync_wait(
        ex::when_all(
            ex::schedule(sch)
                | ex::then([]() -> int {
                    throw std::runtime_error{"вычисление A провалилось"};
                    return 0;
                }),
            ex::schedule(sch)
                | ex::then([]() -> int {
                    // В реальном коде здесь была бы проверка stop_token
                    // и ранний выход. Для примера просто возвращаем значение.
                    return 99;
                })
        )
    );

    // when_all завершился через set_error — result == std::nullopt,
    // а исключение переброшено при выходе из sync_wait.
    // Ниже это не выполнится:
    if (result) {
        auto [r1, r2] = *result;
        std::cout << r1 << ' ' << r2 << '\n';
    } else {
        std::cout << "результат недоступен (отмена)\n";
    }
}
// Как перехватить ошибку — оберните sync_wait в try/catch:
// try { ex::sync_wait(...); }
// catch (const std::runtime_error& e) { std::cerr << e.what(); }

#include <execution>
#include <iostream>

int expensive_query() {
    // Представьте: сетевой запрос, парсинг файла и т.п.
    return 100;
}

int main() {
    namespace ex = std::execution;

    // Исходный сендер можно подключить только один раз.
    // split делает его копируемым — обе копии разделяют
    // одно базовое вычисление.
    auto shared_source = ex::split(
        ex::just(0) | ex::then([]([[maybe_unused]] int) {
            return expensive_query();
        })
    );

    // Строим два независимых продолжения от одного источника:
    auto pipeline_a = shared_source | ex::then([](int v) { return v + 1; });
    auto pipeline_b = shared_source | ex::then([](int v) { return v * 2; });

    // Запускаем оба параллельно через when_all:
    auto result = ex::sync_wait(
        ex::when_all(
            std::move(pipeline_a),
            std::move(pipeline_b)
        )
    );

    // expensive_query() вызывается ровно один раз.
    // Результат (100) доступен обоим продолжениям.
    auto [a, b] = *result;
    std::cout << "a = " << a << '\n';  // 101
    std::cout << "b = " << b << '\n';  // 200
}

