#include <execution>
#include <system_error>
#include <iostream>

// Симулируем операцию, которая может вернуть std::error_code.
// just_error создаёт сендер, завершающийся через set_error.
auto fetch_data(bool fail) {
    namespace ex = std::execution;
    if (fail) {
        // Тип ошибки — std::error_code, НЕ exception_ptr.
        return ex::just_error(
            std::make_error_code(std::errc::connection_refused)
        );
    }
    return ex::just(std::make_error_code({}))  // «нет ошибки», но для симметрии типов
        | ex::then([](std::error_code) { return 42; });
}

int main() {
    namespace ex = std::execution;

    // upon_error: fn принимает std::error_code, возвращает int-значение.
    // Лямбда должна принимать именно std::error_code — иначе ошибка компиляции.
    auto pipeline =
        fetch_data(/*fail=*/true)
        | ex::upon_error([](std::error_code ec) -> int {
            std::cerr << "Ошибка: " << ec.message() << '\n';
            return -1;  // значение по умолчанию вместо ошибки
        });

    auto result = ex::sync_wait(std::move(pipeline));
    // Канал set_error был преобразован в set_value(-1),
    // поэтому result содержит std::optional<std::tuple<int>>.
    if (result) {
        std::cout << "Результат: " << std::get<0>(*result) << '\n';
    }
}

#include <execution>
#include <system_error>
#include <iostream>
#include <string>

// Симулируем два источника: основной всегда падает.
auto primary_source() {
    namespace ex = std::execution;
    return ex::just_error(
        std::make_error_code(std::errc::no_such_file_or_directory)
    );
}

auto fallback_source() {
    namespace ex = std::execution;
    // Запасной источник возвращает строку-результат.
    return ex::just(std::string{"данные из кэша"});
}

int main() {
    namespace ex = std::execution;

    // let_error: fn возвращает НОВЫЙ СЕНДЕР, а не значение.
    // Это ключевое отличие от upon_error.
    auto pipeline =
        primary_source()
        | ex::let_error([](std::error_code ec) {
            if (ec == std::errc::no_such_file_or_directory) {
                std::cerr << "Основной источник недоступен, использую кэш\n";
                return fallback_source();  // <-- возвращаем новый сендер
            }
            // При другой ошибке — пробрасываем её дальше.
            return ex::just_error(ec);
        });

    auto result = ex::sync_wait(std::move(pipeline));
    if (result) {
        std::cout << "Получено: " << std::get<0>(*result) << '\n';
    }
}

#include <execution>
#include <stop_token>  // std::stop_source, std::stop_token (C++20)
#include <iostream>
#include <thread>
#include <chrono>

// Долгая «операция»: периодически проверяет stop_token.
// В реальном коде это был бы кастомный сендер с встроенной проверкой.
auto long_operation() {
    namespace ex = std::execution;
    // Для примера просто возвращаем значение через just.
    // Реальная реализация кастомного сендера проверяла бы get_stop_token(receiver).
    return ex::just(std::string{"результат долгой операции"});
}

int main() {
    namespace ex = std::execution;

    std::stop_source cancel_source;  // внешний источник отмены

    // stop_when связывает пайплайн с внешним stop_token.
    // Если cancel_source.request_stop() будет вызван,
    // пайплайн получит stop_requested и завершится через set_stopped.
    auto cancelable_pipeline = ex::stop_when(
        long_operation(),
        cancel_source.get_token()
    );

    // В реальном сценарии отмену могла бы запросить кнопка UI:
    // std::thread([&]{
    //     std::this_thread::sleep_for(std::chrono::milliseconds{50});
    //     cancel_source.request_stop();
    // }).detach();

    // Здесь мы НЕ отменяем — пайплайн должен завершиться нормально.
    auto result = ex::sync_wait(std::move(cancelable_pipeline));

    if (result) {
        std::cout << "Завершено: " << std::get<0>(*result) << '\n';
    } else {
        // Если бы cancel_source.request_stop() был вызван,
        // sync_wait вернул бы std::nullopt (канал set_stopped).
        std::cout << "Операция была отменена\n";
    }
}

