// Требует C++26 std::execution (P2300).
// Показано как пример на основе спецификации — не компилировалось.
#include <execution>
#include <print>
#include <stdexcept>

// Представьте, что это настоящие асинхронные операции:
auto positive_path(int x) {
    // Возвращает отправитель, производящий x * 2
    return std::execution::just(x * 2);
}

auto negative_path() {
    // Возвращает отправитель, сигнализирующий об ошибке
    return std::execution::just_error(
        std::make_exception_ptr(
            std::runtime_error{"отрицательный ввод недопустим"}
        )
    );
}

int main() {
    namespace ex = std::execution;

    // let_value: fn возвращает НОВЫЙ ОТПРАВИТЕЛЬ, а не обычный int.
    // Какой отправитель — зависит от значения: в этом и суть.
    auto pipeline =
        ex::just(42)
        | ex::let_value([](int x) {
            // fn должна вернуть отправитель:
            if (x > 0)
                return positive_path(x);   // → just(84)
            else
                return negative_path();    // → just_error(...)
        });

    // При just(42) выполняется положительная ветка → 84.
    auto result = ex::sync_wait(std::move(pipeline));
    std::println("{}", std::get<0>(*result)); // 84

    // Если бы мы начали с just(-1), сработал бы negative_path()
    // и sync_wait пробросил бы runtime_error.
}

// Демонстрирует let_error: fn получает ошибку и возвращает отправитель.
// В отличие от upon_error (fn возвращает обычное значение),
// fn в let_error может запустить полноценную асинхронную операцию.
#include <execution>
#include <print>
#include <stdexcept>

// Симулирует асинхронный резервный запрос (возвращает отправитель):
auto query_fallback_service() {
    return std::execution::just(-1); // резервное значение
}

int main() {
    namespace ex = std::execution;

    // Основной отправитель: немедленно сигнализирует об ошибке.
    auto primary = ex::just_error(
        std::make_exception_ptr(std::runtime_error{"основная операция не удалась"})
    );

    auto pipeline =
        std::move(primary)
        | ex::let_error([](std::exception_ptr) {
            // fn получает ошибку, возвращает новый отправитель.
            // Здесь мы запускаем асинхронный резервный путь.
            // (В продакшне это мог бы быть отправитель сетевого запроса.)
            return query_fallback_service();
        });

    // Ошибка перехвачена; вместо неё выполняется резервный отправитель.
    auto result = ex::sync_wait(std::move(pipeline));
    std::println("{}", std::get<0>(*result)); // -1

    // Для сравнения: upon_error потребовал бы, чтобы fn вернула -1 напрямую.
    // let_error позволяет fn вернуть query_fallback_service()
    // — асинхронную операцию, а не обычное значение.
}

// Концептуальная иллюстрация гарантии нулевого выделения.
// Все состояния операций встроены — без выделения в куче.
#include <execution>
#include <print>

int main() {
    namespace ex = std::execution;

    // Каждый шаг | оборачивает предыдущий отправитель в новый тип.
    // Компилятор знает полный тип на этапе компиляции.
    auto pipeline =
        ex::just(1)                             // JustSender<int>
        | ex::then([](int x){ return x + 1; }) // ThenSender<JustSender<int>, L1>
        | ex::then([](int x){ return x * 3; }) // ThenSender<ThenSender<...>, L2>
        | ex::let_value([](int x) {             // LetValueSender<..., L3>
            return ex::just(x - 1);
          });

    // connect() возвращает объект, тип которого кодирует ВСЕ четыре состояния.
    // Его размер известен на этапе компиляции. Он живёт на стеке ниже:
    auto op = ex::connect(std::move(pipeline), /* какой-то приёмник */ 0);
    // sizeof(op) известен на этапе компиляции — нет new, нет shared_ptr.
    // Все четыре подсостояния упакованы встроенно внутри op.

    // На практике sync_wait делает connect + start за нас:
    auto result = ex::sync_wait(
        ex::just(1)
        | ex::then([](int x){ return x + 1; })  // 2
        | ex::then([](int x){ return x * 3; })  // 6
        | ex::let_value([](int x) {
            return ex::just(x - 1);              // 5
          })
    );
    std::println("{}", std::get<0>(*result)); // 5

    // Для сравнения: каждый вызов std::async выделяет
    // управляющий блок shared_ptr в куче.
    // Цепочка из 4 вызовов async = 4 выделения в куче.
    // Этот конвейер = 0 выделений в куче.
}

